fixes.origin:
target = self.store / ref

with open(target, "r", encoding="utf-8") as handle:
    return handle.read()

fixes.replacement:
base = self.store.resolve()
target = (self.store / ref).resolve()
if base not in target.parents and target != base:
    raise ValueError("invalid document path")

with open(target, "r", encoding="utf-8") as handle:
    return handle.read()
